// Test case to reproduce the bug described in the issue
// The bug: $derived reactivity breaks with "createSubscriber" after its teardown/destroy has been called at least once

import { createSubscriber, $derived, $state, flushSync } from '../../../packages/svelte/src/index-client.js';

// Simplified test case based on the bug report
class TestStore {
    #subscribe;
    #value = $state(0);
    subscribeCount = 0;
    unsubscribeCount = 0;

    constructor() {
        this.#subscribe = createSubscriber((update) => {
            this.subscribeCount++;
            console.log('Subscriber started', this.subscribeCount);

            return () => {
                this.unsubscribeCount++;
                console.log('Cleanup called', this.unsubscribeCount);
            };
        });
    }

    get current() {
        this.#subscribe();
        return this.#value;
    }

    set value(v) {
        this.#value = v;
    }
}

// Test the bug scenario
async function testBug() {
    console.log('=== Testing createSubscriber + $derived bug ===');

    // Create a derived store that creates a new TestStore instance
    let trigger = $state(0);
    let derivedStore = $derived(new TestStore());

    // First access - should start subscriber
    console.log('First access to derivedStore.current');
    let value1 = derivedStore.current;
    console.log('Value:', value1, 'Subscriptions:', derivedStore.subscribeCount, 'Unsubscribers:', derivedStore.unsubscribeCount);

    // Update the derived store by changing trigger
    console.log('Updating trigger to cause re-evaluation...');
    trigger = 1;
    flushSync();

    // Second access - after teardown should have been called
    console.log('Second access after trigger change');
    let value2 = derivedStore.current;
    console.log('Value:', value2, 'Subscriptions:', derivedStore.subscribeCount, 'Unsubscribers:', derivedStore.unsubscribeCount);

    // Test if reactivity still works
    console.log('Testing reactivity...');
    derivedStore.value = 42;
    flushSync();

    let value3 = derivedStore.current;
    console.log('Value after update:', value3, 'Subscriptions:', derivedStore.subscribeCount, 'Unsubscribers:', derivedStore.unsubscribeCount);

    // Check if the bug is present
    if (value3 !== 42) {
        console.log('❌ BUG CONFIRMED: Reactivity is broken! Value should be 42 but is', value3);
        return false;
    }

    console.log('✅ Reactivity works correctly');
    return true;
}

// Run the test
testBug().then(result => {
    console.log('Test result:', result ? 'PASS' : 'FAIL');
}).catch(err => {
    console.error('Test error:', err);
});

