import { flushSync } from 'svelte';
import { test } from '../../test';

export default test({
	async test({ assert, target, logs }) {
		const buttons = target.querySelectorAll('button');
		const triggerBtn = buttons[0];
		const updateBtn = buttons[1];
		const toggleBtn = buttons[2];
		const valueDiv = target.querySelector('#value');
		const teardownDiv = target.querySelector('#teardown-count');
		const subscribeDiv = target.querySelector('#subscribe-count');

		// Initial state
		assert.equal(valueDiv.textContent, '0');
		assert.equal(teardownDiv.textContent, 'Teardowns: 0');
		assert.equal(subscribeDiv.textContent, 'Subscriptions: 1');

		// Toggle visibility to trigger teardown
		toggleBtn.click();
		flushSync();
		await Promise.resolve();
		await Promise.resolve();

		// Should have triggered teardown (subscribers = 0)
		toggleBtn.click();
		flushSync();
		await Promise.resolve();
		await Promise.resolve();

		// Check that teardown was called
		assert.equal(teardownDiv.textContent, 'Teardowns: 1');

		// Now update the store value - this should still work after teardown
		updateBtn.click();
		flushSync();
		await Promise.resolve();

		// This is where the bug appears - value should be 1 but might still be 0
		assert.equal(valueDiv.textContent, '1', 'Reactivity should work after teardown');

		// Try trigger update to re-evaluate derived
		triggerBtn.click();
		flushSync();
		await Promise.resolve();

		// Value should still be 1 (no change from trigger)
		assert.equal(valueDiv.textContent, '1');

		// Update store value again
		updateBtn.click();
		flushSync();
		await Promise.resolve();

		// Should now be 2
		assert.equal(valueDiv.textContent, '2', 'Reactivity should continue to work after multiple teardowns');
	}
});

